#include <stdio.h>
#include <stdbool.h>
#define MAX 2000010

bool isPrime[MAX];

void sieve() {
    for (int i = 0; i < MAX; ++i) isPrime[i] = true;
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i < MAX; ++i) {
        if (isPrime[i]) {
            for (int j = i * i; j < MAX; j += i) isPrime[j] = false;
        }
    }
}

int main() {
    sieve();
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int L, R; scanf("%d %d", &L, &R);
        int x = R + 1;
        while (!isPrime[x]) ++x;
        printf("%d\n", x);
    }
    return 0;
}

